import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient';

const Lancamento = () => {
  const [form, setForm] = useState({
    descricao: '', valor_total: 0, loja: '', parcelado: false, num_parcelas: 1
  });

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    // 1. Salva a Compra Principal
    const { data: compra, error } = await supabase
      .from('compras')
      .insert([form])
      .select();

    if (error) return console.error(error);

    // 2. Lógica para gerar parcelas no banco (Exemplo rápido)
    if (form.parcelado) {
      const valorParcela = form.valor_total / form.num_parcelas;
      // Aqui você faria um loop para inserir na tabela 'parcelas'
      console.log(`Gerando ${form.num_parcelas} parcelas de R$ ${valorParcela}`);
    }
  };

  return (
    <div className="container">
      <h2>Novo Lançamento</h2>
      <form onSubmit={handleSubmit}>
        <input placeholder="Descrição" onChange={e => setForm({...form, descricao: e.target.value})} />
        <input type="number" placeholder="Valor Total" onChange={e => setForm({...form, valor_total: e.target.value})} />
        <label>
          <input type="checkbox" onChange={e => setForm({...form, parcelado: e.target.checked})} /> Parcelado?
        </label>
        {form.parcelado && (
          <input type="number" placeholder="Nº de Parcelas" onChange={e => setForm({...form, num_parcelas: e.target.value})} />
        )}
        <button type="submit">Salvar Despesa</button>
      </form>
    </div>
  );
};

export default Lancamento;
